import{c as s,Q as l,j as n,m as e}from"./chunks/framework.BXc4yaFE.js";const k=JSON.parse('{"title":"Claude Code SKILL 設計最佳實踐","description":"","frontmatter":{"title":"Claude Code SKILL 設計最佳實踐","type":"prompt"},"headers":[],"relativePath":"research/prompts/skill-design-prompt.md","filePath":"research/prompts/skill-design-prompt.md","lastUpdated":1779894392000}'),i={name:"research/prompts/skill-design-prompt.md"};function p(t,a,o,r,c,d){return l(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="claude-code-skill-設計最佳實踐" tabindex="-1">Claude Code SKILL 設計最佳實踐 <a class="header-anchor" href="#claude-code-skill-設計最佳實踐" aria-label="Permalink to &quot;Claude Code SKILL 設計最佳實踐&quot;">​</a></h1><blockquote><p>來源：research/tweets/ SKILL 分類，基於 9 篇文章 核心數據：247 個 Skills 測試，9.3% pass rate（@Mnilax）；900k+ 社群 Skills</p></blockquote><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><p><strong>何時使用</strong>：設計新 SKILL 前、稽核現有 Skill 庫、建立 Skill 篩選標準時。 <strong>貼入哪裡</strong>：<code>.claude/skills/</code> 目錄下的 <code>.md</code> 檔案；也可直接作為 Skill 設計 checklist。</p><hr><h2 id="核心設計原則" tabindex="-1">核心設計原則 <a class="header-anchor" href="#核心設計原則" aria-label="Permalink to &quot;核心設計原則&quot;">​</a></h2><h3 id="_1-capability-vs-discipline-雙框架-mnilax" tabindex="-1">1. Capability vs Discipline 雙框架（@Mnilax） <a class="header-anchor" href="#_1-capability-vs-discipline-雙框架-mnilax" aria-label="Permalink to &quot;1. Capability vs Discipline 雙框架（@Mnilax）&quot;">​</a></h3><ul><li><strong>Capability Skills</strong>：補足 Claude 本身無法完成的任務（最小集合，約 20%）</li><li><strong>Discipline Skills</strong>：強制一致性風格、工作流紀律（最大品質槓桿，約 80%）</li><li>決策問題：「沒有這個 Skill，Claude 完全做不到嗎？」是 → Capability；否 → Discipline</li></ul><h3 id="_2-量化評估勝於主觀感受-mnilax" tabindex="-1">2. 量化評估勝於主觀感受（@Mnilax） <a class="header-anchor" href="#_2-量化評估勝於主觀感受-mnilax" aria-label="Permalink to &quot;2. 量化評估勝於主觀感受（@Mnilax）&quot;">​</a></h3><ul><li>雙門檻：品質提升 ≥ 1.5 分（10分制）+ 時間節省 ≥ 30%，兩者同時達標才保留</li><li>測試週期：新 Skill 試用 30 天，未觸發一次則停用</li><li>失敗模式分類：① Cursor-style prompts（口語規則，非結構化）② 功能重複（與其他 Skill 衝突）③ Hook spec 過期 ④ 惡意/被入侵（12% 社群 Skills 有問題）</li></ul><h3 id="_3-活躍數量上限-5-7-個-mnilax" tabindex="-1">3. 活躍數量上限 5-7 個（@Mnilax） <a class="header-anchor" href="#_3-活躍數量上限-5-7-個-mnilax" aria-label="Permalink to &quot;3. 活躍數量上限 5-7 個（@Mnilax）&quot;">​</a></h3><ul><li>超過 9 個 = overhead ~13,500 tokens per task，回報遞減</li><li>Tier S 必裝（經實測）：frontend-design、superpowers、simplify、skill-creator、web-design-guidelines</li><li>安裝順序：Week 1 基礎 4 個 → Week 2 領域 1-2 個 → Week 3+ 按需評估</li></ul><h3 id="_4-真實範例-抽象規則-berryxia" tabindex="-1">4. 真實範例 &gt; 抽象規則（@berryxia） <a class="header-anchor" href="#_4-真實範例-抽象規則-berryxia" aria-label="Permalink to &quot;4. 真實範例 &gt; 抽象規則（@berryxia）&quot;">​</a></h3><ul><li>「任何重複告訴 Claude 的，都值得變成 Skill」</li><li>建構七步驟：反向提問 → 反向發現 → 對話轉化 → <strong>範例優先</strong>（一個好例子 &gt; 十條描述）→ 三輪迭代 → 加自查清單 → 手動通讀</li><li>Skills 2.0 機制：內建評估斷言、A/B 測試、觸發詞自動優化</li></ul><h3 id="_5-yaml-frontmatter-控制行為-zodchiii" tabindex="-1">5. YAML frontmatter 控制行為（@zodchiii） <a class="header-anchor" href="#_5-yaml-frontmatter-控制行為-zodchiii" aria-label="Permalink to &quot;5. YAML frontmatter 控制行為（@zodchiii）&quot;">​</a></h3><ul><li><code>description</code> 是給模型的觸發詞，不是給人讀的說明</li><li><code>allowed-tools</code> 明確限制 Skill 可用的工具範圍</li><li>命名：<code>.claude/skills/&lt;command-name&gt;.md</code> → 對應 <code>/&lt;command-name&gt;</code> 呼叫</li></ul><h3 id="_6-蘇格拉底式一次一問-khazix0918" tabindex="-1">6. 蘇格拉底式一次一問（@Khazix0918） <a class="header-anchor" href="#_6-蘇格拉底式一次一問-khazix0918" aria-label="Permalink to &quot;6. 蘇格拉底式一次一問（@Khazix0918）&quot;">​</a></h3><ul><li>複雜任務 Skill：先問至 95% 確信度再執行，不並行提問</li><li>規劃時間 &gt; 執行時間：「規劃 2h，執行 10m，審查 1h」</li><li>子 Agent 雙審查：需求符合度 + 程式碼品質，兩個獨立審查點</li></ul><h3 id="_7-context-decay-閾值管理-nateherk" tabindex="-1">7. Context Decay 閾值管理（@nateherk） <a class="header-anchor" href="#_7-context-decay-閾值管理-nateherk" aria-label="Permalink to &quot;7. Context Decay 閾值管理（@nateherk）&quot;">​</a></h3><ul><li>30 分鐘後 context 品質明顯衰減（~40% token 成為雜訊）</li><li>Skill 設計需包含 <code>/compact</code> 觸發時機或明確的 context reset 提示</li><li>Context Mode（content-mode Skill）可將 Playwright 56KB → 精煉版本</li></ul><hr><h2 id="prompt-範本" tabindex="-1">Prompt 範本 <a class="header-anchor" href="#prompt-範本" aria-label="Permalink to &quot;Prompt 範本&quot;">​</a></h2><h3 id="skill-設計-prompt-貼入新-skill-檔案時使用" tabindex="-1">SKILL 設計 Prompt（貼入新 Skill 檔案時使用） <a class="header-anchor" href="#skill-設計-prompt-貼入新-skill-檔案時使用" aria-label="Permalink to &quot;SKILL 設計 Prompt（貼入新 Skill 檔案時使用）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># [Skill 名稱]</span></span>
<span class="line"><span>&gt; 分類：Capability / Discipline（選一）</span></span>
<span class="line"><span>&gt; 觸發詞：[何種情況下 Claude 應自動使用]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 目標</span></span>
<span class="line"><span>[一句話：這個 Skill 解決什麼具體問題，對應的失敗模式是什麼]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 前置條件</span></span>
<span class="line"><span>- [使用前需要具備的 context 或檔案]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 執行步驟</span></span>
<span class="line"><span>1. [具體步驟，可執行]</span></span>
<span class="line"><span>2. [每步有明確的完成判斷標準]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 自查清單（完成後驗證）</span></span>
<span class="line"><span>- [ ] [可驗證的條件1]</span></span>
<span class="line"><span>- [ ] [可驗證的條件2]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 禁止事項</span></span>
<span class="line"><span>- 不要 [具體禁止行為，基於實測失敗模式]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 成功標準</span></span>
<span class="line"><span>[「夠好」的定義，5 分鐘內可判斷]</span></span></code></pre></div><h3 id="週期稽核-prompt-每-30-天執行" tabindex="-1">週期稽核 Prompt（每 30 天執行） <a class="header-anchor" href="#週期稽核-prompt-每-30-天執行" aria-label="Permalink to &quot;週期稽核 Prompt（每 30 天執行）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分析最近 30 天內以下 Skills 的使用記錄：</span></span>
<span class="line"><span>[列出當前 active skills]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>對每個 Skill 回答：</span></span>
<span class="line"><span>1. 觸發次數（0 次 → 停用候選）</span></span>
<span class="line"><span>2. 品質提升評分（1-10）</span></span>
<span class="line"><span>3. 時間節省百分比（估計）</span></span>
<span class="line"><span>4. 是否與其他 Skill 有功能重疊？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>輸出：保留清單、停用清單、新需求清單（各附理由）</span></span>
<span class="line"><span>上限：保留後 active skills ≤ 7 個</span></span></code></pre></div><hr><h2 id="關鍵引用" tabindex="-1">關鍵引用 <a class="header-anchor" href="#關鍵引用" aria-label="Permalink to &quot;關鍵引用&quot;">​</a></h2><blockquote><p>「Discipline skills 大多數人只裝 Capability」—— @Mnilax（2026-05-05）</p></blockquote><blockquote><p>「任何重複告訴 Claude 的，都值得變成 Skill」—— @berryxia（2026-03-26）</p></blockquote><blockquote><p>「弱模型因規範化流程得到最大提升」—— @Khazix0918（2026-03-26）</p></blockquote><blockquote><p>「每步驟 50 字的 prompt 濃縮為 7-15 個字元的指令」—— @zodchiii（2026-05-04）</p></blockquote>`,32)])])}const u=s(i,[["render",p]]);export{k as __pageData,u as default};
